// Load existing vocab
const vocabFile = JSON.parse(fs.readFileSync('data/challenge/day-08/vocabulary.json', 'utf8'));
const existingWords = vocabFile.words;
const existingSet = new Set(existingWords.map(w => w.word.toLowerCase().trim()));

// Build new word entries
function buildEntry(w, id) {
  return {
    id,
    word: w.word,
    hindi: w.hindi,
    simpleMeaning: w.sm,
    ipa: w.ipa,
    verbForms: {
      base: w.base || "-",
      s3: w.s3 || "-",
      ing: w.ing || "-",
      past: w.past || "-",
      pastParticiple: w.pp || "-"
    },
    synonyms: w.syn || [],
    antonyms: w.ant || [],
    sentences: {
      daily: w.daily || "-",
      office: w.office || "-",
      interview: w.interview || "-",
      business: w.business || "-",
      formal: w.formal || "-",
      informal: w.informal || "-"
    },
    usageNote: w.note || "-",
    cefrLevel: w.cefr || "B1"
  };
}

const combined = [...existingWords];
for (const w of newWords) {
  const key = w.word.toLowerCase().trim();
  if (existingSet.has(key)) continue;
  existingSet.add(key);
  combined.push(buildEntry(w, combined.length + 1));
  if (combined.length >= 950) break;
}

// Fix IDs
combined.forEach((w, i) => { w.id = i + 1; });

console.log('Vocab total:', combined.length);

vocabFile.totalWords = combined.length;
vocabFile.words = combined;
fs.writeFileSync('data/challenge/day-08/vocabulary.json', JSON.stringify(vocabFile, null, 2));

// Verify JSON
JSON.parse(fs.readFileSync('data/challenge/day-08/vocabulary.json'));
console.log('✓ vocabulary.json valid');

